// =======================================
// Calculate_Quote
// Préparer les règles métier
// Version : MVP 1.1
// =======================================

const now = new Date().toISOString();

const validation = $("Validation contexte avant calcul").first()?.json || {};
const context = validation.context || {};

const referentielItems = $("Référentiel").all();
const grilleItems = $("Grille Tarifaire").all();

const errors = [];

function normalizeText(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[–—]/g, "-")
    .replace(/≤/g, "<=")
    .replace(/≥/g, ">=")
    .trim();
}

function toNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? number : null;
}

function getFields(item) {
  return item?.json?.fields || item?.json || {};
}

const rules = {
  tva: null,
  marge: null,

  saisonnalite: {
    basse: null,
    moyenne: null,
    haute: null,
    tres_haute: null
  },

  urgence: {
    prioritaire_14j: null,
    urgent_15_30j: null,
    normal_31_90j: null,
    plus_90j: null
  },

  capacite: {
    jusqua_19: null,
    de_20_a_53: null,
    de_54_a_63: null,
    de_64_a_67: null,
    de_68_a_85: null
  },

  grille_tarifaire: [],

  formule_longue_distance: {
    seuil_km: 180,
    coefficient_distance: 2,
    prix_km_ht: 2.5
  }
};

for (const item of referentielItems) {
  const fields = getFields(item);

  const parametre = normalizeText(fields["Paramètre"]);
  const categorie = normalizeText(fields["Catégorie"]);
  const valeur = toNumber(fields["Valeur"]);

  if (valeur === null) continue;

  if (parametre === "tva" || categorie === "fiscalite") {
    rules.tva = valeur;
    continue;
  }

  if (parametre === "marge" || categorie === "commercial") {
    rules.marge = valeur;
    continue;
  }

  if (categorie === "saisonnalite") {
    if (parametre.includes("basse")) rules.saisonnalite.basse = valeur;
    else if (parametre.includes("moyen")) rules.saisonnalite.moyenne = valeur;
    else if (parametre.includes("tres haute")) rules.saisonnalite.tres_haute = valeur;
    else if (parametre.includes("haute")) rules.saisonnalite.haute = valeur;
  }

  if (categorie === "urgence") {
    if (parametre.includes("prioritaire") || parametre.includes("14")) {
      rules.urgence.prioritaire_14j = valeur;
    } else if (parametre.includes("urgent") || parametre.includes("15") || parametre.includes("30")) {
      rules.urgence.urgent_15_30j = valeur;
    } else if (parametre.includes("normal") || parametre.includes("31")) {
      rules.urgence.normal_31_90j = valeur;
    } else if (parametre.includes(">90") || parametre.includes("90")) {
      rules.urgence.plus_90j = valeur;
    }
  }

  if (categorie === "capacite") {
    if (parametre.includes("19")) rules.capacite.jusqua_19 = valeur;
    else if (parametre.includes("20") || parametre.includes("53")) rules.capacite.de_20_a_53 = valeur;
    else if (parametre.includes("54") || parametre.includes("63")) rules.capacite.de_54_a_63 = valeur;
    else if (parametre.includes("64") || parametre.includes("67")) rules.capacite.de_64_a_67 = valeur;
    else if (parametre.includes("68") || parametre.includes("85")) rules.capacite.de_68_a_85 = valeur;
  }
}

for (const item of grilleItems) {
  const fields = getFields(item);

  const distanceMaxKm = toNumber(fields["Distance max (km)"]);
  const prixForfaitHt = toNumber(fields["Prix forfait HT"]);

  if (distanceMaxKm === null || prixForfaitHt === null) continue;

  rules.grille_tarifaire.push({
    palier: fields["Palier"] || String(distanceMaxKm),
    distance_max_km: distanceMaxKm,
    prix_forfait_ht: prixForfaitHt,
    type_formule: fields["Type formule"] || "Transfert simple"
  });
}

rules.grille_tarifaire.sort((a, b) => a.distance_max_km - b.distance_max_km);

if (rules.tva === null) errors.push({ code: "MISSING_TVA", field: "rules.tva" });
if (rules.marge === null) errors.push({ code: "MISSING_MARGE", field: "rules.marge" });
if (rules.grille_tarifaire.length === 0) errors.push({ code: "MISSING_GRID", field: "rules.grille_tarifaire" });

for (const [field, value] of Object.entries({
  "rules.saisonnalite.basse": rules.saisonnalite.basse,
  "rules.saisonnalite.moyenne": rules.saisonnalite.moyenne,
  "rules.saisonnalite.haute": rules.saisonnalite.haute,
  "rules.saisonnalite.tres_haute": rules.saisonnalite.tres_haute,
  "rules.urgence.prioritaire_14j": rules.urgence.prioritaire_14j,
  "rules.urgence.urgent_15_30j": rules.urgence.urgent_15_30j,
  "rules.urgence.normal_31_90j": rules.urgence.normal_31_90j,
  "rules.urgence.plus_90j": rules.urgence.plus_90j,
  "rules.capacite.jusqua_19": rules.capacite.jusqua_19,
  "rules.capacite.de_20_a_53": rules.capacite.de_20_a_53,
  "rules.capacite.de_54_a_63": rules.capacite.de_54_a_63,
  "rules.capacite.de_64_a_67": rules.capacite.de_64_a_67,
  "rules.capacite.de_68_a_85": rules.capacite.de_68_a_85
})) {
  if (value === null) errors.push({ code: "MISSING_RULE", field });
}

if (errors.length > 0) {
  return [
    {
      json: {
        success: false,
        message: "Règles tarifaires incomplètes.",
        error: "INVALID_PRICING_RULES",
        errors,
        context: {
          ...context,
          last_tool: "Calculate_Quote",
          last_error_at: now
        }
      }
    }
  ];
}

return [
  {
    json: {
      success: true,
      message: "Règles tarifaires préparées.",
      context: {
        ...context,
        pricing_rules: rules,
        last_update_at: now
      }
    }
  }
];

// =======================================
// Calculate_Quote
// Calcul du devis
// Version : MVP 1.0
// Calcul déterministe — aucun LLM
// =======================================

const now = new Date().toISOString();

const input = $input.first()?.json || {};
const context = input.context || {};
const rules = context.pricing_rules || {};

const errors = [];

function round2(value) {
  return Math.round((Number(value) + Number.EPSILON) * 100) / 100;
}

function normalizeText(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[–—]/g, "-")
    .replace(/\s*-\s*/g, "-")
    .trim();
}

function daysBetween(dateStart, dateEnd) {
  const start = new Date(dateStart);
  const end = new Date(dateEnd);

  if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) return null;

  return Math.ceil((end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
}

const distanceKm = Number(context.distance?.distance_km);
const nbPassagers = Number(context.trajet?.nb_passagers);
const typeTrajet = context.trajet?.type_trajet || "aller-simple";
const typeTrajetNormalized = normalizeText(typeTrajet);
const dateDepart = context.trajet?.date_depart;

const dateDemande =
  context.trajet?.date_demande ||
  context.metadata?.created_at ||
  context.last_update_at ||
  now;

if (!Number.isFinite(distanceKm) || distanceKm <= 0) errors.push({ code: "INVALID_DISTANCE", field: "distance.distance_km" });
if (!Number.isFinite(nbPassagers) || nbPassagers <= 0) errors.push({ code: "INVALID_PASSENGERS", field: "trajet.nb_passagers" });
if (!dateDepart) errors.push({ code: "MISSING_DATE_DEPART", field: "trajet.date_depart" });

if (errors.length > 0) {
  return [
    {
      json: {
        success: false,
        message: "Impossible de calculer le devis.",
        error: "INVALID_CONTEXT_FOR_QUOTE",
        errors,
        context
      }
    }
  ];
}

let prixBaseTransfertSimpleHt = 0;
let formuleUtilisee = null;
let selectedPalier = null;

const seuilLongueDistance = Number(rules.formule_longue_distance?.seuil_km || 180);
const coefficientDistance = Number(rules.formule_longue_distance?.coefficient_distance || 2);
const prixKmHt = Number(rules.formule_longue_distance?.prix_km_ht || 2.5);

if (distanceKm <= seuilLongueDistance) {
  selectedPalier = [...(rules.grille_tarifaire || [])]
    .sort((a, b) => a.distance_max_km - b.distance_max_km)
    .find((palier) => distanceKm <= Number(palier.distance_max_km));

  if (!selectedPalier) {
    return [
      {
        json: {
          success: false,
          message: "Aucun palier tarifaire ne correspond à la distance.",
          error: "NO_MATCHING_PRICING_TIER",
          context
        }
      }
    ];
  }

  prixBaseTransfertSimpleHt = Number(selectedPalier.prix_forfait_ht);
  formuleUtilisee = `Forfait palier ${selectedPalier.distance_max_km} km`;
} else {
  prixBaseTransfertSimpleHt = round2(distanceKm * coefficientDistance * prixKmHt);
  formuleUtilisee = `Longue distance : (${distanceKm} × ${coefficientDistance}) × ${prixKmHt}`;
}

let multiplicateurTrajet = 1;

if (
  typeTrajetNormalized.includes("aller-retour") ||
  typeTrajetNormalized.includes("allerretour")
) {
  multiplicateurTrajet = 2;
}

const prixBaseHt = round2(prixBaseTransfertSimpleHt * multiplicateurTrajet);

const month = new Date(dateDepart).getMonth() + 1;

let saisonName = "Moyenne";
let coefSaison = rules.saisonnalite?.moyenne ?? 0;

if ([11, 1, 2, 8].includes(month)) {
  saisonName = "Basse";
  coefSaison = rules.saisonnalite.basse;
} else if ([12, 10, 9].includes(month)) {
  saisonName = "Moyenne";
  coefSaison = rules.saisonnalite.moyenne;
} else if ([3, 4, 7].includes(month)) {
  saisonName = "Haute";
  coefSaison = rules.saisonnalite.haute;
} else if ([5, 6].includes(month)) {
  saisonName = "Très haute";
  coefSaison = rules.saisonnalite.tres_haute;
}

const delaiJours = daysBetween(dateDemande, dateDepart);

let urgenceName = "Non déterminée";
let coefUrgence = 0;

if (delaiJours !== null) {
  if (delaiJours <= 14) {
    urgenceName = "Prioritaire";
    coefUrgence = rules.urgence.prioritaire_14j;
  } else if (delaiJours <= 30) {
    urgenceName = "Urgent";
    coefUrgence = rules.urgence.urgent_15_30j;
  } else if (delaiJours <= 90) {
    urgenceName = "Normal";
    coefUrgence = rules.urgence.normal_31_90j;
  } else {
    urgenceName = "Plus de 90 jours";
    coefUrgence = rules.urgence.plus_90j;
  }
}

let capaciteName = null;
let coefCapacite = 0;

if (nbPassagers <= 19) {
  capaciteName = "≤19 passagers";
  coefCapacite = rules.capacite.jusqua_19;
} else if (nbPassagers <= 53) {
  capaciteName = "20–53 passagers";
  coefCapacite = rules.capacite.de_20_a_53;
} else if (nbPassagers <= 63) {
  capaciteName = "54–63 passagers";
  coefCapacite = rules.capacite.de_54_a_63;
} else if (nbPassagers <= 67) {
  capaciteName = "64–67 passagers";
  coefCapacite = rules.capacite.de_64_a_67;
} else if (nbPassagers <= 85) {
  capaciteName = "68–85 passagers";
  coefCapacite = rules.capacite.de_68_a_85;
} else {
  return [
    {
      json: {
        success: false,
        message: "Demande hors périmètre de calcul automatique.",
        error: "CAPACITY_OUT_OF_RANGE",
        context
      }
    }
  ];
}

const margePourcentage = Number(rules.marge);
const tvaPourcentage = Number(rules.tva);

const totalCoef = Number(coefSaison) + Number(coefUrgence) + Number(coefCapacite);

const montantApresCoefficientsHt = round2(prixBaseHt * (1 + totalCoef / 100));
const montantMarge = round2(montantApresCoefficientsHt * (margePourcentage / 100));
const totalHt = round2(montantApresCoefficientsHt + montantMarge);
const montantTva = round2(totalHt * (tvaPourcentage / 100));
const totalTtc = round2(totalHt + montantTva);

const quoteId = `DEV-${context.demande_id || "NA"}-${Date.now()}`;

const calculationDetails = {
  resume: `Formule: ${formuleUtilisee} | Base HT: ${prixBaseHt} € | Saison: ${saisonName} ${coefSaison}% | Urgence: ${urgenceName} ${coefUrgence}% | Capacité: ${capaciteName} ${coefCapacite}% | Total HT: ${totalHt} € | TVA: ${montantTva} € | TTC: ${totalTtc} €`,
  lignes: [
    { ordre: 1, libelle: "Formule utilisée", formule: formuleUtilisee, montant_ht: prixBaseTransfertSimpleHt },
    { ordre: 2, libelle: "Multiplicateur trajet", formule: `${typeTrajet} × ${multiplicateurTrajet}`, montant_ht: prixBaseHt },
    { ordre: 3, libelle: "Coefficient saison", formule: `${saisonName} = ${coefSaison}%`, montant_ht: round2(prixBaseHt * (coefSaison / 100)) },
    { ordre: 4, libelle: "Coefficient urgence", formule: `${urgenceName} = ${coefUrgence}%`, montant_ht: round2(prixBaseHt * (coefUrgence / 100)) },
    { ordre: 5, libelle: "Coefficient capacité", formule: `${capaciteName} = ${coefCapacite}%`, montant_ht: round2(prixBaseHt * (coefCapacite / 100)) },
    { ordre: 6, libelle: "Marge commerciale", formule: `${montantApresCoefficientsHt} × ${margePourcentage}%`, montant_ht: montantMarge },
    { ordre: 7, libelle: "TVA", formule: `${totalHt} × ${tvaPourcentage}%`, montant_ht: montantTva },
    { ordre: 8, libelle: "Prix TTC", formule: `${totalHt} + ${montantTva}`, montant_ttc: totalTtc }
  ]
};

const { pricing_rules, ...contextWithoutPricingRules } = context;

const updatedContext = {
  ...contextWithoutPricingRules,

  devis: {
    ...(context.devis || {}),
    quote_id: quoteId,
    formule_utilisee: formuleUtilisee,
    prix_base_ht: prixBaseHt,
    prix_base_transfert_simple_ht: prixBaseTransfertSimpleHt,
    multiplicateur_trajet: multiplicateurTrajet,
    coef_saison: coefSaison,
    coef_urgence: coefUrgence,
    coef_capacite: coefCapacite,
    total_coef: totalCoef,
    montant_apres_coefficients_ht: montantApresCoefficientsHt,
    marge_pourcentage: margePourcentage,
    montant_marge: montantMarge,
    tva_pourcentage: tvaPourcentage,
    montant_tva: montantTva,
    total_ht: totalHt,
    total_ttc: totalTtc,
    currency: "EUR",
    calculated: true,
    calculated_at: now,
    calculation_details: calculationDetails
  },

  pricing: {
    formula_used: formuleUtilisee,
    selected_palier: selectedPalier,
    season: {
      name: saisonName,
      coef: coefSaison
    },
    urgency: {
      name: urgenceName,
      coef: coefUrgence,
      days_before_departure: delaiJours
    },
    capacity: {
      name: capaciteName,
      coef: coefCapacite
    },
    margin: {
      percent: margePourcentage,
      amount: montantMarge
    },
    vat: {
      percent: tvaPourcentage,
      amount: montantTva
    }
  },

  last_tool: "Calculate_Quote",
  last_update_at: now
};

return [
  {
    json: {
      success: true,
      message: "Devis calculé.",
      context: updatedContext,
      result: {
        entity: "quote",
        quote_id: quoteId,
        total_ht: totalHt,
        total_ttc: totalTtc,
        currency: "EUR"
      }
    }
  }
];

// =======================================
// Calculate_Quote
// Normalize_Input_WF006
// Version : MVP 1.1
// Entrée attendue : { context: {...} }
// =======================================

const input = $input.first()?.json || {};
const now = new Date().toISOString();

const context = input.context || {};

return [
  {
    json: {
      success: true,
      message: "Entrée Calculate_Quote normalisée.",
      context: {
        ...context,
        last_update_at: now
      }
    }
  }
];

// =======================================
// WF_006_Calculate_Quote
// Fusion Airtable Devis + Contexte
// Version : 3.0
// Contrat de sortie standard NeoTravel
// =======================================

const now = new Date().toISOString();

const record = $input.first()?.json || {};
const fields = record.fields || {};

const quoteId = fields["Quote_Id"] || null;
const devisId = fields["Devis ID"] || null;

// =======================================
// Reconstruction du contexte
// =======================================

const context = {

  airtable: {
    devis_record_id: record.id || null,
    devis_id: devisId,
    quote_id: quoteId
  },

  devis: {

    airtable_record_id: record.id || null,

    devis_id: devisId,

    quote_id: quoteId,

    formule_utilisee: fields["Formule utilisée"] || null,

    prix_base_ht: fields["Prix HT"] || null,

    total_ht: fields["Sous-total HT"] || fields["Prix HT"] || null,

    montant_tva: fields["Montant TVA"] || null,

    total_ttc: fields["Prix TTC"] || null,

    tva_pourcentage: fields["TVA (%)"] || null,

    marge_pourcentage: fields["Marge (%)"] || null,

    montant_marge: fields["Montant marge"] || null,

    status: fields["Statut devis"] || null,

    currency: "EUR"

  },

  pdf: {
    generated: false
  },

  steps: {
    quote_calculated: true,
    pdf_generated: false
  },

  last_tool: "WF_006_Calculate_Quote",

  last_update_at: now

};

// =======================================
// Retour Tool
// =======================================

return [
  {
    json: {

      success: true,

      status: "QUOTE_CALCULATED",

      tool: "WF_006_Calculate_Quote",

      version: "3.0",

      timestamp: now,

      context,

      message: "Le devis a été calculé avec succès.",

      next_action: "call_tool",

      next_workflow: "WF_007_Check_Completude_Avant_PDF",

      next_payload: {
        context
      },

      error: null

    }
  }
];

// =======================================
// Calculate_Quote
// Préparer Airtable Devis
// Version : MVP 1.1
// =======================================

const input = $input.first()?.json || {};
const context = input.context || {};
const devis = context.devis || {};

const fields = {
  "Quote_Id": devis.quote_id,
  "Lead_Id": context.airtable?.demande_record_id || null,
  "Formule utilisée": devis.formule_utilisee,
  "Prix HT": devis.montant_apres_coefficients_ht,
  "Marge (%)": devis.marge_pourcentage,
  "Montant marge": devis.montant_marge,
  "TVA (%)": devis.tva_pourcentage,
  "Montant TVA": devis.montant_tva,
  "Sous-total HT": devis.total_ht,
  "Prix TTC": devis.total_ttc,
  "Statut devis": "En attente de validation commerciale"
};

return [
  {
    json: {
      success: true,
      message: "Payload Airtable Devis préparé.",
      context,
      fields,
      result: input.result || null
    }
  }
];

// =======================================
// Calculate_Quote
// Validation contexte avant calcul
// Version : MVP 1.0
// =======================================

const input = $input.first()?.json || {};
const now = new Date().toISOString();

const context = input.context || {};
const errors = [];

function isEmpty(value) {
  return value === undefined || value === null || value === "";
}

function isValidNumber(value) {
  return !isEmpty(value) && Number.isFinite(Number(value));
}

if (!context.airtable?.demande_record_id) {
  errors.push({
    code: "MISSING_DEMANDE_RECORD_ID",
    field: "context.airtable.demande_record_id",
    message: "Le record Airtable de la demande est obligatoire."
  });
}

if (!context.distance?.distance_km || !isValidNumber(context.distance.distance_km)) {
  errors.push({
    code: "MISSING_DISTANCE",
    field: "context.distance.distance_km",
    message: "La distance est obligatoire pour calculer le devis."
  });
}

if (!context.trajet?.nb_passagers || !isValidNumber(context.trajet.nb_passagers)) {
  errors.push({
    code: "MISSING_PASSENGERS",
    field: "context.trajet.nb_passagers",
    message: "Le nombre de passagers est obligatoire."
  });
}

if (!context.trajet?.date_depart) {
  errors.push({
    code: "MISSING_DATE_DEPART",
    field: "context.trajet.date_depart",
    message: "La date de départ est obligatoire."
  });
}

if (!context.trajet?.type_trajet) {
  errors.push({
    code: "MISSING_TYPE_TRAJET",
    field: "context.trajet.type_trajet",
    message: "Le type de trajet est obligatoire."
  });
}

const nbPassagers = Number(context.trajet?.nb_passagers);

if (Number.isFinite(nbPassagers) && nbPassagers > 85) {
  return [
    {
      json: {
        success: false,
        message: "La demande dépasse le périmètre de calcul automatique.",
        error: "CAPACITY_REQUIRES_COMMERCIAL_REVIEW",
        context: {
          ...context,
          commercial: {
            ...(context.commercial || {}),
            validation_required: true,
            reason: "CAPACITY_OVER_85"
          },
          last_tool: "Calculate_Quote",
          last_error_at: now
        },
        result: {
          entity: "quote",
          manual_review: true,
          reason: "CAPACITY_OVER_85"
        }
      }
    }
  ];
}

if (errors.length > 0) {
  return [
    {
      json: {
        success: false,
        message: "Données insuffisantes pour calculer le devis.",
        error: "QUOTE_VALIDATION_FAILED",
        errors,
        context: {
          ...context,
          last_tool: "Calculate_Quote",
          last_error_at: now
        }
      }
    }
  ];
}

return [
  {
    json: {
      success: true,
      message: "Contexte validé pour calcul du devis.",
      context: {
        ...context,
        last_update_at: now
      }
    }
  }
];

// =======================================
// Calculate_Quote
// Retour erreur Airtable
// Version : MVP 1.0
// =======================================

const now = new Date().toISOString();

let prepared = {};
try {
  prepared = $("Préparer Airtable Devis").first()?.json || {};
} catch (error) {
  prepared = {};
}

const context = prepared.context || {};
const inputError = $input.first()?.json || {};

return [
  {
    json: {
      success: false,
      message: "Devis calculé mais impossible à enregistrer dans Airtable.",
      error: "AIRTABLE_CREATE_QUOTE_FAILED",
      details: inputError.error?.message || inputError.message || null,
      context: {
        ...context,
        last_tool: "Calculate_Quote",
        last_error_at: now
      },
      result: {
        entity: "quote",
        saved_to_airtable: false
      }
    }
  }
